mapper.select:
SELECT trader.NAME trader_name,party.user_name username,party.user_code usercode,party.role_name rolename,trader_order.UUID id,trader_order.STATE state, trader_order.VOLUME_OPEN volume_open,trader_order.ORDER_NO order_no,DATE_FORMAT(trader_order.CREATE_TIME, '%Y-%m-%d %H:%i:%S') create_time,DATE_FORMAT(trader_order.CLOSE_TIME, '%Y-%m-%d %H:%i:%S') close_time, trader_order.TRADE_AVG_PRICE trade_avg_price,trader_order.close_avg_price CLOSE_AVG_PRICE,trader_order.CLOSE_TIME close_time,trader_order.CHANGE_RATIO change_ratio, trader_order.DIRECTION direction,trader_order.PROFIT profit,item.NAME itemname, trader_order.DEL_FLAG del_flag, trader_order.LEVER_RATE lever_rate, trader.FOLLOWER_NOW follow_now, trader.FOLLOWER_MAX follow_max FROM T_TRADER_ORDER trader_order LEFT JOIN TZ_USER party ON party.user_id = trader_order.PARTY_ID LEFT JOIN T_TRADER trader ON trader.PARTY_ID = trader_order.PARTY_ID LEFT JOIN T_ITEM item ON trader_order.SYMBOL=item.SYMBOL WHERE 1 = 1
AND trader.NAME =#{name}
and party.role_name =#{rolename}
AND (party.user_name like CONCAT('%',#{username},'%') OR party.user_code like CONCAT('%',#{username},'%'))
ORDER BY trader_order.CREATE_TIME DESC LIMIT #{pageNo}, #{pageSize}
